export default function Home() {
  const [wifiData, setWifiData] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await fetch('http://localhost:8000/api/wifi');
        if (!res.ok) throw new Error('Failed to fetch Wi-Fi data');
        const data = await res.json();
        setWifiData(data);
        setError(null);
      } catch (err) {
        setError(err.message);
        setWifiData(null);
      }
    };

    const interval = setInterval(fetchData, 3000);
    fetchData(); // Initial call

    return () => clearInterval(interval);
  }, []);

  if (error) {
    return (
      <div className="p-4 text-red-500">Error: {error}</div>
    );
  }

  if (!wifiData) {
    return (
      <div className="p-4">Loading Wi-Fi statistics...</div>
    );
  }

  return (
    <div className="p-6 max-w-md mx-auto bg-white rounded shadow">
      <h1 className="text-2xl font-bold mb-4">Wi-Fi Network Statistics</h1>
      <div className="space-y-3">
        <div>
          <span className="font-medium">SSID:</span> {wifiData.ssid}
        </div>
        <div>
          <span className="font-medium">BSSID:</span> {wifiData.bssid}
        </div>
        <div>
          <span className="font-medium">Signal Strength:</span> {wifiData.rssi} dBm
        </div>
        <div>
          <span className="font-medium">Channel:</span> {wifiData.channel}
        </div>
        <div>
          <span className="font-medium">Transmit Rate:</span> {wifiData.tx_rate} Mbps
        </div>
        <div>
          <span className="font-medium">Security:</span> {wifiData.security || 'None'}
        </div>
      </div>
    </div>
  );
}"}
